#!/bin/bash
# ================================================================
# MOEX Bond Platform — One-Command Installer
# ================================================================
# Просто запустите на сервере:  bash moex_install.sh
# Всё включено: файлы проекта, схема БД, настройки nginx/systemd
# ================================================================
set -e

APP_DIR="/opt/moex-bond-platform"
DB_NAME="moex_bonds"
DB_USER="moex"
DB_PASS="moex123"

echo "=========================================="
echo "  MOEX Bond Platform — Installer"
echo "=========================================="

# 1. System packages
echo "[1/7] Installing system packages..."
apt-get update -qq
DEBIAN_FRONTEND=noninteractive apt-get install -y -qq python3.12 python3.12-venv python3.12-dev \
    postgresql postgresql-contrib nginx git curl 2>/dev/null

# 2. PostgreSQL
echo "[2/7] Setting up PostgreSQL..."
systemctl enable postgresql
systemctl start postgresql

sudo -u postgres psql -tc "SELECT 1 FROM pg_roles WHERE rolname='${DB_USER}'" | grep -q 1 || \
    sudo -u postgres psql -c "CREATE USER ${DB_USER} WITH PASSWORD '${DB_PASS}';"

sudo -u postgres psql -lqt | cut -d \| -f 1 | grep -qw ${DB_NAME} || \
    sudo -u postgres psql -c "CREATE DATABASE ${DB_NAME} OWNER ${DB_USER};"

sudo -u postgres psql -d ${DB_NAME} -c "CREATE EXTENSION IF NOT EXISTS pg_trgm;" 2>/dev/null || true

# 3. Write project files
echo "[3/7] Writing project files..."
mkdir -p ${APP_DIR}/.streamlit

echo '  schema.sql...'
cat > '${APP_DIR}/schema.sql' << 'B64EOF'


B64EOF
base64 -d '${APP_DIR}/schema.sql' > '${APP_DIR}/schema.sql.dec' && mv '${APP_DIR}/schema.sql.dec' '${APP_DIR}/schema.sql'
echo '  requirements.txt...'
echo 'cmVxdWVzdHM+PTIuMzIuMwpwYW5kYXM+PTIuMi4zCm9wZW5weXhsPj0zLjEuNQpwc3ljb3BnMi1iaW5hcnk+PTIuOS45CnN0cmVhbWxpdD49MS40MC4wClNRTEFsY2hlbXk+PTIuMC4zNgpweXRob24tZGF0ZXV0aWw+PTIuOS4wCnN0LWFnZ3JpZD49MC4zLjQK' | base64 -d > '${APP_DIR}/requirements.txt'
echo '  data_collector.py...'
cat > '${APP_DIR}/data_collector.py' << 'B64EOF'






B64EOF
base64 -d '${APP_DIR}/data_collector.py' > '${APP_DIR}/data_collector.py.dec' && mv '${APP_DIR}/data_collector.py.dec' '${APP_DIR}/data_collector.py'
echo '  streamlit_app.py...'
cat > '${APP_DIR}/streamlit_app.py' << 'B64EOF'




B64EOF
base64 -d '${APP_DIR}/streamlit_app.py' > '${APP_DIR}/streamlit_app.py.dec' && mv '${APP_DIR}/streamlit_app.py.dec' '${APP_DIR}/streamlit_app.py'
echo '  .streamlit/config.toml...'
echo '' | base64 -d > '${APP_DIR}/.streamlit/config.toml'

# 4. Database schema
echo "[4/7] Creating database schema..."
sudo -u postgres psql -d ${DB_NAME} -f ${APP_DIR}/schema.sql

# 5. Python virtual environment
echo "[5/7] Creating Python environment..."
python3.12 -m venv ${APP_DIR}/venv
source ${APP_DIR}/venv/bin/activate
pip install --upgrade pip -q
pip install -r ${APP_DIR}/requirements.txt -q 2>&1 | tail -3

# 6. Systemd service
echo "[6/7] Configuring systemd service..."
cat > /etc/systemd/system/moex-bond-screener.service << 'SVCEOF'
[Unit]
Description=MOEX Bond Screener (Streamlit)
After=network.target postgresql.service

[Service]
Type=simple
User=root
WorkingDirectory=/opt/moex-bond-platform
Environment=DATABASE_URL=postgresql://moex:moex123@localhost:5432/moex_bonds
Environment=PATH=/opt/moex-bond-platform/venv/bin:/usr/local/bin:/usr/bin:/bin
ExecStart=/opt/moex-bond-platform/venv/bin/streamlit run /opt/moex-bond-platform/streamlit_app.py \
    --server.port 8501 \
    --server.address 0.0.0.0 \
    --server.headless true \
    --server.enableCORS false \
    --server.enableXsrfProtection false \
    --browser.gatherUsageStats false
Restart=always
RestartSec=5

[Install]
WantedBy=multi-user.target
SVCEOF

systemctl daemon-reload
systemctl enable moex-bond-screener

# 7. Nginx
echo "[7/7] Configuring Nginx..."
cat > /etc/nginx/sites-available/moex-bond-screener << 'NGINXEOF'
server {
    listen 80;
    server_name _;

    location / {
        proxy_pass http://127.0.0.1:8501;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 86400;
    }

    client_max_body_size 50M;
}
NGINXEOF

ln -sf /etc/nginx/sites-available/moex-bond-screener /etc/nginx/sites-enabled/
rm -f /etc/nginx/sites-enabled/default
nginx -t 2>/dev/null && systemctl restart nginx

# Cron for daily data collection
(crontab -l 2>/dev/null; echo "0 2 * * * /opt/moex-bond-platform/venv/bin/python3.12 /opt/moex-bond-platform/data_collector.py >> /var/log/moex-collector.log 2>&1") | crontab -

echo ""
echo "=========================================="
echo "  INSTALLATION COMPLETE"
echo "=========================================="
echo ""
echo "  Next step: import initial data"
echo "  Run: /opt/moex-bond-platform/venv/bin/python3.12 /opt/moex-bond-platform/data_collector.py /path/to/initial_data.xlsx"
echo ""
echo "  Then start: systemctl start moex-bond-screener"
echo ""
echo "  Web: http://YOUR_SERVER_IP:8501/"
echo "  Via Nginx: http://YOUR_SERVER_IP/"
echo ""
echo "  Management:"
echo "    systemctl status moex-bond-screener"
echo "    systemctl restart moex-bond-screener"
echo "    journalctl -u moex-bond-screener -f"
